/* supabase.min.js — synchronous CDN loader for file:// context
   Loads the Supabase JS client from the CDN via synchronous XHR so that
   window.supabase is available immediately when supabase-config.js runs. */
(function () {
  if (window.supabase && typeof window.supabase.createClient === 'function') return;
  try {
    var xhr = new XMLHttpRequest();
    xhr.open('GET', 'https://cdn.jsdelivr.net/npm/@supabase/supabase-js@2.45.1/dist/umd/supabase.min.js', false); // synchronous
    xhr.send(null);
    if (xhr.status === 200) {
      // eslint-disable-next-line no-eval
      eval(xhr.responseText);
    } else {
      console.error('[supabase.min.js] Failed to load Supabase from CDN. Status:', xhr.status);
    }
  } catch (e) {
    console.error('[supabase.min.js] Error loading Supabase:', e);
  }
})();
